cat /home/armel/Projects/OSS/bmad-module-skill-forge/src/skf-campaign/assets/campaign-state-schema.json | python3 -c "import json,sys; d=json.load(sys.stdin); print(json.dumps(d.get('properties',{}).get('skills',{}).get('items',{}).get('properties',{}), indent=2))" 2>/dev/null || echo "Trying different path..."; python3 -c "
import json,sys
with open('/home/armel/Projects/OSS/bmad-module-skill-forge/src/skf-campaign/assets/campaign-state-schema.json') as f:
    d = json.load(f)
# Find skills schema
def find_skills(obj, path=''):
    if isinstance(obj, dict):
        if 'skills' in obj:
            return obj['skills']
        for k, v in obj.items():
            r = find_skills(v, f'{path}.{k}')
            if r: return r
    return None
s = find_skills(d)
if s:
    print(json.dumps(s, indent=2))
else:
    print('skills not found, printing top-level keys')
    print(json.dumps(list(d.keys()), indent=2))
"

